g-guide//_next/static/media/cs-verification-agent.46e86ffe.png",height:691,width:1030,blurDataURL:"data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAgAAAAFCAIAAAD38zoCAAAAdklEQVR42gUASQ6CMLCfAYFI28mUdsp0I0KN20E9eNDE//+CiO/v/3p/LPGhabjrU9dz21LXixDLzEVrdG5GCWVUd7TqKMW6XsgvSsH19pRAGk2tD7RBABjyYZrIOc65Ko3kIwAK5pjyklLJ5YTGD8O4bWdj7A6KvBq3GoztFQAAAABJRU5ErkJggg==",blurWidth:8,blurHeight:5},u=a(39013);let p=[{depth:2,value:"Planning",id:"planning"},{depth:2,value:"Orchestrator & Sub-agent Architecture",id:"orchestrator--sub-agent-architecture"},{depth:2,value:"Context Retrieval and Agentic Search",id:"context-retrieval-and-agentic-search"},{depth:2,value:"Context Engineering",id:"context-engineering"},{depth:2,value:"Verification",id:"verification"},{depth:2,value:"Final Words",id:"final-words"}];function _createMdxContent(e){let n=Object.assign({h1:"h1",p:"p",a:"a",img:"img",h2:"h2",em:"em"},(0,s.a)(),e.components);return(0,t.jsxs)(t.Fragment,{children:[(0,t.jsx)(n.h1,{children:"Deep Agents"}),"\n","\n",(0,t.jsx)(n.p,{children:"Most agents today are shallow."}),"\n",(0,t.jsx)(n.p,{children:"They easily break down on long, multi-step problems (e.g., deep research or agentic coding)."}),"\n",(0,t.jsx)(n.p,{children:"That’s changing fast!"}),"\n",(0,t.jsx)(n.p,{children:'We’re entering the era of "Deep Agents", systems that strategically plan, remember, and delegate intelligently for solving very complex problems.'}),"\n",(0,t.jsxs)(n.p,{children:["We at the ",(0,t.jsx)(n.a,{href:"https://academy.dair.ai/",children:"DAIR.AI Academy"})," and other folks from ",(0,t.jsx)(n.a,{href:"https://docs.langchain.com/labs/deep-agents/overview",children:"LangChain"}),", ",(0,t.jsx)(n.a,{href:"https://www.anthropic.com/engineering/building-agents-with-the-claude-agent-sdk",children:"Claude Code"}),", as well as more recently, individuals like ",(0,t.jsx)(n.a,{href:"https://www.philschmid.de/agents-2.0-deep-agents",children:"Philipp Schmid"}),", have been documenting this idea."]}),"\n",(0,t.jsxs)(n.p,{children:["Here is an example of a deep agent built to power the ",(0,t.jsx)(n.a,{href:"https://academy.dair.ai/",children:"DAIR.AI Academy's"})," customer support system intended for students to ask questions regarding our trainings and courses:"]}),"\n",(0,t.jsx)(n.p,{children:(0,t.jsx)(n.img,{alt:"deep-agent",placeholder:"blur",src:l})}),"\n",(0,t.jsx)(u.UW,{type:"info",emoji:"\uD83D\uDCDA",children:(0,t.jsxs)(n.p,{children:["This post is based on our new course ",(0,t.jsx)(n.a,{href:"https://academy.dair.ai/courses/building-effective-ai-agents",children:'"Building Effective AI Agents with n8n"'}),", which provides comprehensive insights, downloadable templates, prompts, and advanced tips into designing and implementing deep agents."]})}),"\n",(0,t.jsx)(n.p,{children:"Here’s roughly the core idea behind Deep Agents (based on my own thoughts and notes that I've gathered from others):"}),"\n",(0,t.jsx)(n.h2,{id:"planning",children:"Planning"}),"\n",(0,t.jsx)(n.p,{children:(0,t.jsx)(n.img,{alt:"cs-planning",placeholder:"blur",src:d})}),"\n",(0,t.jsx)(n.p,{children:"Instead of reasoning ad-hoc inside a single context window, Deep Agents maintain structured task plans they can update, retry, and recover from. Think of it as a living to-do list that guides the agent toward its long-term goal. To experience this, just try out Claude Code or Codex for planning; the results are significantly better once you enable it before executing any task."}),"\n",(0,t.jsx)(n.p,{children:"We have also written recently on the power of brainstorming for longer with Claude Code, and this shows the power of planning, expert context, and human-in-the-loop (your expertise gives you an important edge when working with deep agents). Planning will also be critical for long-horizon problems (think agents for scientific discovery, which comes next)."}),"\n",(0,t.jsx)(n.h2,{id:"orchestrator--sub-agent-architecture",children:"Orchestrator & Sub-agent Architecture"}),"\n",(0,t.jsx)(n.p,{children:(0,t.jsx)(n.img,{alt:"cs-subagents",placeholder:"blur",src:c})}),"\n",(0,t.jsxs)(n.p,{children:["One big agent (typically with a very long context) is no longer enough. I've seen ",(0,t.jsx)(n.a,{href:"https://cognition.ai/blog/dont-build-multi-agents",children:"arguments"})," against multi-agent systems and in favor of monolithic systems, but I'm skeptical about this."]}),"\n",(0,t.jsx)(n.p,{children:"The orchestrator-sub-agent architecture is one of the most powerful LLM-based agentic architectures you can leverage today for any domain you can imagine. An orchestrator manages specialized sub-agents such as search agents, coders, KB retrievers, analysts, verifiers, and writers, each with its own clean context and domain focus."}),"\n",(0,t.jsx)(n.p,{children:"The orchestrator delegates intelligently, and subagents execute efficiently. The orchestrator integrates their outputs into a coherent result. Claude Code popularized the use of this approach for coding and sub-agents, which, it turns out, are particularly useful for efficiently managing context (through separation of concerns)."}),"\n",(0,t.jsxs)(n.p,{children:["I wrote a few notes on the power of using orchestrator and subagents ",(0,t.jsx)(n.a,{href:"https://x.com/omarsar0/status/1960877597191245974",children:"here"})," and ",(0,t.jsx)(n.a,{href:"https://x.com/omarsar0/status/1971975884077965783",children:"here"}),"."]}),"\n",(0,t.jsx)(n.h2,{id:"context-retrieval-and-agentic-search",children:"Context Retrieval and Agentic Search"}),"\n",(0,t.jsx)(n.p,{children:(0,t.jsx)(n.img,{alt:"persistent-storage",placeholder:"blur",src:g})}),"\n",(0,t.jsx)(n.p,{children:"Deep Agents don’t rely on conversation history alone. They store intermediate work in external memory like files, notes, vectors, or databases, letting them reference what matters without overloading the model’s context. High-quality structured memory is a thing of beauty."}),"\n",(0,t.jsxs)(n.p,{children:["Take a look at recent works like ",(0,t.jsx)(n.a,{href:"https://arxiv.org/abs/2509.25140",children:"ReasoningBank"})," and ",(0,t.jsx)(n.a,{href:"https://arxiv.org/abs/2510.04618",children:"Agentic Context Engineering"})," for some really cool ideas on how to better optimize memory building and retrieval. Building with the orchestrator-subagents architecture means that you can also leverage hybrid memory techniques (e.g., agentic search + semantic search), and you can let the agent decide what strategy to use."]}),"\n",(0,t.jsx)(n.h2,{id:"context-engineering",children:"Context Engineering"}),"\n",(0,t.jsxs)(n.p,{children:["One of the worst things you can do when interacting with these types of agents is underspecified instructions/prompts. Prompt engineering was and is important, but we will use the new term ",(0,t.jsx)(n.a,{href:"https://www.promptingguide.ai/guides/context-engineering-guide",children:"context engineering"})," to emphasize the importance of building context for agents. The instructions need to be more explicit, detailed, and intentional to define when to plan, when to use a sub-agent, how to name files, and how to collaborate with humans. Part of context engineering also involves efforts around structured outputs, system prompt optimization, compacting context, evaluating context effectiveness, and ",(0,t.jsx)(n.a,{href:"https://www.anthropic.com/engineering/writing-tools-for-agents",children:"optimizing tool definitions"}),"."]}),"\n",(0,t.jsxs)(n.p,{children:["Read our previous guide on context engineering to learn more: ",(0,t.jsx)(n.a,{href:"https://www.promptingguide.ai/guides/context-engineering-guide",children:"Context Engineering Deep Dive"})]}),"\n",(0,t.jsx)(n.h2,{id:"verification",children:"Verification"}),"\n",(0,t.jsx)(n.p,{children:(0,t.jsx)(n.img,{alt:"verification agent",placeholder:"blur",src:m})}),"\n",(0,t.jsx)(n.p,{children:"Next to context engineering, verification is one of the most important components of an agentic system (though less often discussed). Verification boils down to verifying outputs, which can be automated (LLM-as-a-Judge) or done by a human. Because of the effectiveness of modern LLMs at generating text (in domains like math and coding), it's easy to forget that they still suffer from hallucination, sycophancy, prompt injection, and a number of other issues. Verification helps with making your agents more reliable and more production-ready. You can build good verifiers by leveraging systematic evaluation pipelines."}),"\n",(0,t.jsx)(n.h2,{id:"final-words",children:"Final Words"}),"\n",(0,t.jsx)(n.p,{children:"This is a huge shift in how we build with AI agents. Deep agents also feel like an important building block for what comes next: personalized proactive agents that can act on our behalf. I will write more on proactive agents in a future post."}),"\n",(0,t.jsxs)(n.p,{children:["I've been teaching these ideas to agent builders over the past couple of months. If you are interested in more hands-on experience for how to build deep agents check out the new course in our academy: ",(0,t.jsx)(n.a,{href:"https://academy.dair.ai/courses/building-effective-ai-agents",children:"https://academy.dair.ai/courses/building-effective-ai-agents"})]}),"\n",(0,t.jsx)(n.p,{children:"The figures you see in the post describe an agentic RAG system that students need to build for the course final project."}),"\n",(0,t.jsx)(u.UW,{type:"info",emoji:"\uD83D\uDCDA",children:(0,t.jsxs)(n.p,{children:["This post is based on our new course ",(0,t.jsx)(n.a,{href:"https://academy.dair.ai/courses/building-effective-ai-agents",children:'"Building Effective AI Agents with n8n"'}),", which provides comprehensive insights, downloadable templates, prompts, and advanced tips into designing and implementing deep agents."]})}),"\n",(0,t.jsx)(n.p,{children:(0,t.jsx)(n.em,{children:"Written by Elvis Saravia (creator of the Prompting Engineering Guide and co-founder of the DAIR.AI Academy)"})})]})}let h={MDXContent:function(){let e=arguments.le